{"language": "html", "code": "<!DOCTYPE html>
<html lang="ko">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>분기 Pulse Check — 영역별 측정 문항 설계(안)</title>
<link href="https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;600;700&family=IBM+Plex+Mono:wght@400;500&display=swap" rel="stylesheet">
<style>
  :root {
    --bg: #F7F7F5;
    --white: #FFFFFF;
    --ink: #1A1A1A;
    --ink-light: #555;
    --ink-muted: #888;
    --border: #E2E2DC;
    --accent-a: #2563EB;
    --accent-b: #7C3AED;
    --accent-c: #059669;
    --accent-d: #DC2626;
    --accent-a-bg: #EFF6FF;
    --accent-b-bg: #F5F3FF;
    --accent-c-bg: #ECFDF5;
    --accent-d-bg: #FEF2F2;
    --tag-bg: #F0F0EB;
    --branch-bg: #FFFBEB;
    --branch-border: #F59E0B;
    --note-color: #6B6B5E;
  }

  * { margin: 0; padding: 0; box-sizing: border-box; }

  body {
    font-family: 'Noto Sans KR', sans-serif;
    background: var(--bg);
    color: var(--ink);
    padding: 48px 40px;
    min-height: 100vh;
  }

  /* ── HEADER ── */
  .doc-header {
    margin-bottom: 40px;
    padding-bottom: 24px;
    border-bottom: 2px solid var(--ink);
    display: flex;
    justify-content: space-between;
    align-items: flex-end;
  }
  .doc-meta {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 11px;
    color: var(--ink-muted);
    text-align: right;
    line-height: 1.8;
  }
  .doc-title-sub {
    font-size: 13px;
    font-weight: 500;
    color: var(--ink-muted);
    margin-bottom: 6px;
    letter-spacing: 0.05em;
  }
  .doc-title {
    font-size: 26px;
    font-weight: 700;
    letter-spacing: -0.02em;
    line-height: 1.2;
  }
  .doc-diff-badge {
    display: inline-flex;
    align-items: center;
    gap: 6px;
    background: var(--ink);
    color: #fff;
    font-size: 11px;
    font-weight: 600;
    padding: 4px 10px;
    border-radius: 4px;
    margin-top: 8px;
    letter-spacing: 0.04em;
  }

  /* ── DIFF NOTE ── */
  .diff-note {
    background: var(--white);
    border: 1px solid var(--border);
    border-left: 4px solid var(--ink);
    padding: 14px 18px;
    border-radius: 0 8px 8px 0;
    margin-bottom: 36px;
    font-size: 13px;
    color: var(--ink-light);
    line-height: 1.7;
  }
  .diff-note strong { color: var(--ink); }

  /* ── SECTION HEADER ── */
  .section-header {
    display: flex;
    align-items: center;
    gap: 12px;
    margin-bottom: 16px;
    margin-top: 36px;
  }
  .section-badge {
    width: 30px; height: 30px;
    border-radius: 50%;
    display: flex; align-items: center; justify-content: center;
    font-weight: 700; font-size: 14px;
    flex-shrink: 0;
  }
  .badge-a { background: var(--accent-a); color: #fff; }
  .badge-b { background: var(--accent-b); color: #fff; }
  .badge-c { background: var(--accent-c); color: #fff; }
  .badge-d { background: var(--accent-d); color: #fff; }

  .section-title {
    font-size: 16px;
    font-weight: 700;
    letter-spacing: -0.01em;
  }
  .section-count {
    font-size: 12px;
    font-weight: 500;
    color: var(--ink-muted);
    margin-left: 4px;
  }

  /* ── GRID ── */
  .card-grid {
    display: grid;
    gap: 14px;
  }
  .grid-3 { grid-template-columns: repeat(3, 1fr); }
  .grid-2 { grid-template-columns: repeat(2, 1fr); }
  .grid-4 { grid-template-columns: repeat(4, 1fr); }

  /* ── CARD ── */
  .card {
    background: var(--white);
    border: 1px solid var(--border);
    border-radius: 10px;
    padding: 16px;
    position: relative;
    transition: box-shadow 0.15s;
  }
  .card:hover { box-shadow: 0 4px 16px rgba(0,0,0,0.07); }

  .card-top {
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    margin-bottom: 10px;
  }
  .card-label {
    font-size: 12px;
    font-weight: 600;
    color: var(--ink-muted);
    letter-spacing: 0.02em;
    line-height: 1.4;
  }
  .card-num {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 11px;
    font-weight: 500;
    color: var(--ink-muted);
    background: var(--tag-bg);
    padding: 2px 8px;
    border-radius: 4px;
    white-space: nowrap;
    margin-left: 8px;
    flex-shrink: 0;
  }

  /* scale badge */
  .scale-tag {
    font-family: 'IBM Plex Mono', monospace;
    font-size: 10px;
    font-weight: 500;
    padding: 2px 7px;
    border-radius: 4px;
    white-space: nowrap;
  }
  .scale-10 { background: #EFF6FF; color: #1D4ED8; }
  .scale-nps { background: #FFF7ED; color: #C2410C; }
  .scale-open { background: #F0FDF4; color: #166534; }
  .scale-5 { background: #F5F3FF; color: #6D28D9; }

  .card-question {
    font-size: 14px;
    font-weight: 600;
    line-height: 1.55;
    color: var(--ink);
    margin-bottom: 10px;
    min-height: 40px;
  }
  .card-question em {
    font-style: normal;
    border-bottom: 2px solid currentColor;
    opacity: 0.6;
  }

  .card-intent {
    font-size: 11.5px;
    color: var(--note-color);
    line-height: 1.65;
    border-top: 1px solid var(--border);
    padding-top: 8px;
    margin-top: 4px;
  }
  .card-intent .intent-label {
    font-weight: 600;
    color: var(--ink-muted);
    font-size: 10.5px;
    letter-spacing: 0.04em;
    display: block;
    margin-bottom: 3px;
  }

  /* ── BRANCH ── */
  .branch-block {
    background: var(--branch-bg);
    border: 1px solid var(--branch-border);
    border-radius: 7px;
    padding: 10px 12px;
    margin-top: 10px;
  }
  .branch-trigger {
    font-size: 11px;
    font-weight: 600;
    color: #92400E;
    margin-bottom: 6px;
    display: flex;
    align-items: center;
    gap: 5px;
  }
  .branch-trigger::before {
    content: '▶';
    font-size: 8px;
  }
  .branch-options {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 4px;
  }
  .branch-opt {
    font-size: 11px;
    color: var(--ink-light);
    padding: 3px 8px;
    background: rgba(245,158,11,0.1);
    border-radius: 4px;
    display: flex;
    align-items: center;
    gap: 5px;
  }
  .branch-opt::before { content: '○'; font-size: 9px; color: #92400E; }
  .branch-sub-q {
    font-size: 11.5px;
    color: var(--ink);
    font-style: italic;
    margin-top: 6px;
    padding: 6px 10px;
    background: rgba(245,158,11,0.08);
    border-radius: 5px;
    border-left: 3px solid var(--branch-border);
  }

  /* ── SPECIAL: Emotion card ── */
  .emotion-grid {
    display: flex;
    gap: 8px;
    margin: 10px 0;
    flex-wrap: wrap;
  }
  .emotion-chip {
    font-size: 22px;
    width: 38px; height: 38px;
    display: flex; align-items: center; justify-content: center;
    background: var(--tag-bg);
    border-radius: 8px;
    cursor: pointer;
    transition: transform 0.1s;
    border: 2px solid transparent;
  }
  .emotion-chip:hover { transform: scale(1.15); border-color: var(--border); }

  /* NPS bar */
  .nps-bar {
    display: flex;
    gap: 3px;
    margin: 10px 0;
    align-items: center;
  }
  .nps-cell {
    flex: 1;
    height: 24px;
    border-radius: 3px;
    display: flex;
    align-items: center;
    justify-content: center;
    font-size: 10px;
    font-weight: 600;
    color: white;
  }
  .nps-detractor { background: #EF4444; }
  .nps-passive   { background: #F59E0B; }
  .nps-promoter  { background: #10B981; }
  .nps-label-row {
    display: flex;
    justify-content: space-between;
    font-size: 10px;
    color: var(--ink-muted);
    margin-top: 3px;
  }

  /* ── QUARTER DIFF TAG ── */
  .qdiff {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    font-size: 10px;
    font-weight: 600;
    padding: 2px 7px;
    border-radius: 12px;
    margin-right: 4px;
  }
  .qdiff-deep { background: #E0E7FF; color: #3730A3; }
  .qdiff-causal { background: #FCE7F3; color: #9D174D; }
  .qdiff-trend { background: #D1FAE5; color: #065F46; }

  /* ── SECTION DIVIDER ── */
  .section-divider {
    height: 1px;
    background: var(--border);
    margin: 12px 0 28px;
  }

  /* ── FOOTER ── */
  .doc-footer {
    margin-top: 48px;
    padding-top: 20px;
    border-top: 1px solid var(--border);
    display: flex;
    justify-content: space-between;
    align-items: flex-start;
    gap: 24px;
  }
  .legend {
    display: flex;
    flex-wrap: wrap;
    gap: 10px;
    font-size: 11.5px;
  }
  .legend-item {
    display: flex;
    align-items: center;
    gap: 5px;
    color: var(--ink-light);
  }
  .footer-note {
    font-size: 11px;
    color: var(--ink-muted);
    text-align: right;
    line-height: 1.8;
    font-family: 'IBM Plex Mono', monospace;
  }

  /* left accent border per section */
  .card.accent-a { border-top: 3px solid var(--accent-a); }
  .card.accent-b { border-top: 3px solid var(--accent-b); }
  .card.accent-c { border-top: 3px solid var(--accent-c); }
  .card.accent-d-red { border-top: 3px solid var(--accent-d); }
  .card.accent-d-gold { border-top: 3px solid #D97706; }

  @media print {
    body { padding: 24px; background: white; }
    .card { break-inside: avoid; }
  }
</style>
</head>
